{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日2026-05-13付で正式キックオフし、正式発足とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10:00から1時間で開催し、各部署から少なくとも1名参加する（リモート参加可）",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "開発ベンダーはコマツバ・ソリューションズさんを前提に進める",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D4",
      "content": "共通基盤はサクラ商事さんとの共同利用案（第3案）で進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "本番リリース目標を9月末から2026-10-15に変更する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "移行方式は拠点を分けて少しずつ切り替える段階移行で進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "第1フェーズのデータ移行はマスタのみとし、トランザクションデータは旧システムを参照用に残して後フェーズで扱う",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "移行テストと負荷テストはシステムテストに混ぜず別立てで実施する",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D9",
      "content": "障害発生時の一次受け窓口はQAチームにし、一次切り分けまでQAが担う",
      "decided_by": "白鳥 千夏"
    },
    {
      "id": "D10",
      "content": "新システムのユーザー権限は既存ロール定義を流用し、今回の新規設計は行わない",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D11",
      "content": "切替作業は土曜夜に実施し、日曜を予備日にする",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "現場ヒアリング対象部署のリストを表形式で提出する",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A2",
      "task": "検証環境のサーバ調達依頼を提出する",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "API仕様書のドラフトを作成する",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A4",
      "task": "コマツバ・ソリューションズさんの見積で社内稟議を起票する",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A5",
      "task": "サクラ商事さんへの共同利用回答書を作成して送付する",
      "assignee": "桐生 遥",
      "due": "2026-05-22"
    },
    {
      "id": "A6",
      "task": "外部ライセンス費用の再見積を取得し、年契約条件も確認する",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A7",
      "task": "負荷試験用の実行環境を構築する",
