    },
    {
      "id": "A11",
      "task": "移行リハーサルの手順書を作成し、白鳥 千夏にレビューしてもらう",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A12",
      "task": "現場向け説明会の日程案を各拠点の生産管理担当へ当たって作成する",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    },
    {
      "id": "A13",
      "task": "議事録を作成し、全員へ共有する",
      "assignee": "桐生 遥",
      "due": "2026-05-13"
    }
  ],
